-- Built-in data for local and demo environments.

UPDATE `process_definition_config` SET `entity_id` = 'seed_demo_request' WHERE `id` = 'seed_full_test_process';

-- Admin role can access all built-in menus.
SELECT CONCAT("admin_menu_", `id`), "1", `id`, NOW() FROM `sys_menu`
ON DUPLICATE KEY UPDATE `role_id` = `role_id`;
